/* =========================
   ENTRADA
========================= */
const rawText = $json.text || '';

const text = rawText
  .replace(/\u00A0/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

/* =========================
   1. PROCESSO (CNJ)
   PRIORIDADE SEMÂNTICA
========================= */

let numeroProcesso = null;

/**
 * Linha explícita "Processo:"
 * Aceita CNJ cru (20 dígitos)
 * ou CNJ mascarado
 */
const processoLinhaRegex =
  /Processo\s*:\s*(\d{20}|\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/i;

const processoLinhaMatch = text.match(processoLinhaRegex);

if (processoLinhaMatch) {
  const p = processoLinhaMatch[1];

  // CNJ cru → mascara
  if (/^\d{20}$/.test(p)) {
    numeroProcesso =
      `${p.slice(0,7)}-${p.slice(7,9)}.` +
      `${p.slice(9,13)}.${p.slice(13,14)}.` +
      `${p.slice(14,16)}.${p.slice(16,20)}`;
  } else {
    numeroProcesso = p;
  }
} else {
  /**
   * Fallback — CNJ mascarado solto
   * (usado só se não existir "Processo:")
   */
  const cnjFallback =
    text.match(/\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}/);

  if (cnjFallback) {
    numeroProcesso = cnjFallback[0];
  }
}

/* =========================
   2. OFÍCIO REQUISITÓRIO
   (multi-tribunal)
========================= */

const oficioPatterns = [
  /OF[IÍ]CIO\s+REQUISIT[ÓO]RIO\s*(?:n[ºo]\s*)?([\d.]+)/i,
  /REQUISI[CÇ][AÃ]O(?:\s+DE\s+PAGAMENTO)?\s*(?:n[ºo]\s*)?([\d.]+)/i,
  /\b(PRC|RPV)\b\s*(?:n[ºo]\s*)?([\d.]{6,})/i,
  /N[ºo]\s*[:\-]?\s*([\d.]{6,})/i
];

let oficio = null;

for (const regex of oficioPatterns) {
  const match = text.match(regex);
  if (match) {
    oficio = match[2] || match[1];
    break;
  }
}

/* =========================
   3. FALLBACK BRUTO
========================= */
if (!oficio) {
  const brute = text.match(/\b\d{8,}\b/);
  if (brute) oficio = brute[0];
}

/* =========================
   4. NORMALIZAÇÃO
========================= */
if (oficio) {
  oficio = oficio.replace(/[^\d.]/g, '');
}

/* =========================
   SAÍDA (n8n)
========================= */
return [
  {
    json: {
      numeroProcesso,
      oficioRequisitorio: oficio
    }
  }
];

function cpfValido(cpf) {
  if (!cpf) return false;

  cpf = cpf.toString().replace(/\D/g, '');

  if (cpf.length !== 11) return false;

  if (/^(\d)\1{10}$/.test(cpf)) return false;

  let soma = 0;
  let resto;

  // 1º dígito
  for (let i = 0; i < 9; i++) {
    soma += parseInt(cpf[i]) * (10 - i);
  }

  resto = (soma * 10) % 11;
  if (resto === 10) resto = 0;
  if (resto !== parseInt(cpf[9])) return false;

  soma = 0;

  // 2º dígito
  for (let i = 0; i < 10; i++) {
    soma += parseInt(cpf[i]) * (11 - i);
  }

  resto = (soma * 10) % 11;
  if (resto === 10) resto = 0;
  if (resto !== parseInt(cpf[10])) return false;

  return true;
}

function extrairCpfDaUrl(url) {
  if (!url) return null;
  const match = url.match(/cpf=(\d+)/);
  return match ? match[1] : null;
}

const itensValidos = items.filter(item => {
  let cpf = item.json.CPF;

  // Primeiro tenta validar o CPF direto
  if (cpfValido(cpf)) {
    return true;
  }

  // Se inválido, tenta extrair da URL
  const cpfDaUrl = extrairCpfDaUrl(item.json.content);

  if (cpfValido(cpfDaUrl)) {
    // Atualiza o CPF no item para o correto
    item.json.CPF = cpfDaUrl;
    return true;
  }

  return false;
});

if (itensValidos.length === 0) {
  return [];
}

return itensValidos;

const data = items[0].json;

// Usar o CRM vindo no input e normalizar (remove www.)
let crm = 'CRM não identificado';

if (data.crm && typeof data.crm === 'string') {
  crm = data.crm.replace(/^www\./, '');
}

// Normalizar alerta
let alerta = data.alerta || 'Alerta não especificado';

// Subject do email agora usando a variável alerta
const subject = `Alerta – ${alerta} no CRM (${crm})`;

// Corpo do email
const body = `
Prezados,

Informamos que, durante a verificação automática no CRM (${crm}), foi identificado o seguinte alerta:

Alerta: ${alerta}

Detalhes do registro:
- Cliente: ${data.NomeCliente}
- CPF: ${data.CPF}
- Número do Processo: ${data.NumeroProcesso}

Link consultado:
${data.link}

Solicitamos a validação manual do caso ou a regularização para que o fluxo possa prosseguir normalmente.

Atenciosamente,
Desenvolvimento.
`.trim();

// Retorno
return [
  {
    json: {
      crm,
      subject,
      body,
      NomeCliente: data.NomeCliente,
      CPF: data.CPF,
      NumeroProcesso: data.NumeroProcesso,
      alerta,
      link: data.link
    }
  }
];

